1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	const PROCESSING_FEE = 5;
13	const BASE_PREMIUMS: Record<string, number> = {
14	  sword: 100,
15	  amulet: 60,
16	  staff: 80,
17	  potion: 40,
18	};
19	const FIRST_INSURANCE_MULTIPLIER = 1.1;
20	
21	// Round up in MHPCO's favour, guarding against floating-point noise
22	// (e.g. 197.50000000001 should still round to 198, not 199).
23	const roundUpInMHPCOFavor = (amount: number): number =>
24	  Math.ceil(Number(amount.toFixed(6)));
25	
26	export const quote = (
27	  items: Item[],
28	  customer: Customer,
29	  contractIndex: number,
30	): number => {
31	  const policyBase = items.reduce(
32	    (sum, item) => sum + BASE_PREMIUMS[item.type] * FIRST_INSURANCE_MULTIPLIER,
33	    0,
34	  );
35	  const total = policyBase + PROCESSING_FEE;
36	  return roundUpInMHPCOFavor(total);
37	};
38	
39	export const claim = (): number => {
40	  return undefined as unknown as number;
41	};
